def sanitize_directory(dir_path):
    """
    Recursively traverse the directory, remove unwanted files, and handle potential errors.
    """
    try:
        for root, dirs, files in os.walk(dir_path):
            for file in files:
                file_path = os.path.join(root, file)
                if os.path.splitext(file)[1].lower() in UNWANTED_EXTENSIONS:
                    try:
                        os.remove(file_path)
                        print(f"Removed file: {file_path}")
                    except PermissionError:
                        print(f"Permission denied: {file_path}")
                    except FileNotFoundError:
                        print(f"File not found: {file_path}")
                    except Exception as e:
                        print(f"Error removing file: {file_path} - {e}")
    except IsADirectoryError:
        print(f"Directory not found: {dir_path}")
    except PermissionError:
        print(f"Permission denied: {dir_path}")
    except Exception as e:
        print(f"Error sanitizing directory: {dir_path} - {e}")

if __name__ == '__main__':
    sanitize_directory(SANITIZE_DIR)
